const j = $input.first().json;
return [{ json: {
  slackUserId: j.slackUserId,
  channelId: j.channelId,
  thread_ts: j.thread_ts,
  ts: j.ts,
  slackText: `No matching sheet row found for user ${j.slackUserId} on date ${j.date}. I did not update remarks.`
} }];

const j = $('Match Daily Row').first().json;
return [{ json: {
  slackUserId: j.slackUserId,
  channelId: j.channelId,
  thread_ts: j.thread_ts,
  ts: j.ts,
  slackText: `Daily update saved for ${j.date}. Status: ${j.sheetStatus || 'n/a'}. Remarks added in sheet.`
} }];

const target = $('Prepare Daily Update Payload').first().json;
const rows = $input.all().map(i => i.json);

function norm(v) { return String(v ?? '').trim().toLowerCase(); }

const wantedUser = norm(target.slackUserId);
const wantedDate = norm(target.date);
let matchedRow = null;

for (const row of rows) {
  const rowUser = norm(row.slackUserId || row.userId || row.SlackUserId || row.UserID || row.user_id);
  const rowDate = norm(row.date || row.Date || row.activity_date || row.ActivityDate);
  if (rowUser === wantedUser && rowDate === wantedDate) {
    matchedRow = row;
    break;
  }
}

if (!matchedRow) {
  return [{ json: {
    matched: false,
    slackUserId: target.slackUserId,
    date: target.date,
    remarks: target.remarks,
    sheetStatus: target.sheetStatus,
    finalStatus: target.sheetStatus || '',
    channelId: target.channelId,
    thread_ts: target.thread_ts,
    ts: target.ts
  } }];
}

const existingStatus = matchedRow.Status || matchedRow.status || '';
const finalStatus = target.sheetStatus || existingStatus;

return [{ json: {
  ...matchedRow,
  matched: true,
  slackUserId: target.slackUserId,
  date: target.date,
  remarks: target.remarks,
  sheetStatus: target.sheetStatus,
  finalStatus,
  channelId: target.channelId,
  thread_ts: target.thread_ts,
  ts: target.ts
} }];

const ai = $('Code in JavaScript2').first().json;
const TZ = 'Asia/Karachi';
function todayYmdInTz() {
  const p = new Intl.DateTimeFormat('en-CA', { timeZone: TZ, year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(new Date());
  return `${p.find((x) => x.type === 'year').value}-${p.find((x) => x.type === 'month').value}-${p.find((x) => x.type === 'day').value}`;
}
const date = ai.activity_date || todayYmdInTz();

const remarks = (ai.remarks || ai.text || '').trim();
const dailyStatus = (ai.daily_status || '').toLowerCase();

let sheetStatus = '';
if (dailyStatus === 'done') sheetStatus = 'Done';
else if (dailyStatus === 'delayed') sheetStatus = 'Delayed';
else if (dailyStatus === 'in_progress') sheetStatus = 'In Progress';

return [{ json: {
  slackUserId: ai.userId || '',
  date,
  remarks,
  dailyStatus,
  sheetStatus,
  channelId: ai.channelId || '',
  thread_ts: ai.thread_ts || '',
  ts: ai.ts || ''
} }];

// Pehle yeh tha (sirf first item):
