// Process ALL items using map
return inputItems.map((inputItem, index) => {
  // Parse work package data
  const raw = inputItem.json;
  let wp;
  if (raw.data && typeof raw.data === 'string') {
    try { wp = JSON.parse(raw.data); } catch(e) { wp = raw; }
  } else if (raw.data && typeof raw.data === 'object') {
    wp = raw.data;
  } else {
    wp = raw;
  }

  // Get corresponding expand data by index
  const expandData = expandItems[index]?.json || {};

  // Get Slack user info
  const slackUserId = expandData.userId || '';
  const slackUserName = (slackUserMap[slackUserId] || '').toLowerCase().trim();

  // Get OpenProject assignee
  const assigneeTitle = (wp._links?.assignee?.title || wp._links?.assignee?.name || '').toLowerCase().trim();

  // Security Check: Match Slack user with OpenProject assignee
  let isAssignee = false;

  if (!assigneeTitle) {
    // Task has NO assignee - allow anyone to update
    isAssignee = true;
  } else if (slackUserName && assigneeTitle) {
    // Compare names with flexible matching
    const slackParts = slackUserName.split(/\s+/).filter(p => p.length > 1);
    const assigneeParts = assigneeTitle.split(/\s+/).filter(p => p.length > 1);

    // Exact match
    if (slackUserName === assigneeTitle) {
      isAssignee = true;
    }
    // At least 2 name parts match
    else {
      const matchCount = slackParts.filter(sp => assigneeParts.some(ap => ap === sp)).length;
      if (matchCount >= 2) {
        isAssignee = true;
      }
      // First name match with at least 3 characters
      else if (slackParts.length >= 1 && assigneeParts.length >= 1 && 
               slackParts[0] === assigneeParts[0] && slackParts[0].length > 2) {
        isAssignee = true;
      }
    }
  }

  return {
    json: {
      task_id: wp.id || expandData.task_id,
      lockVersion: wp.lockVersion,
      isAssignee,
      slackUserName,
      assigneeTitle,
      channelId: expandData.channelId,
      userId: expandData.userId,
      thread_ts: expandData.thread_ts,
      ts: expandData.ts
    }
  };
});

const prev = $('Code in JavaScript2').first().json;
const taskIds = prev.task_ids || (prev.task_id ? [prev.task_id] : []);
const channelId = prev.channelId || '';
const userId = prev.userId || '';
const threadTs = prev.thread_ts || '';
const ts = prev.ts || '';

if (taskIds.length === 0) {
  return [{ json: { error: 'No task IDs provided', channelId, userId } }];
}

return taskIds.map(id => ({
  json: { task_id: id, channelId, userId, thread_ts: threadTs, ts }
}));

const raw = $input.first().json;
let wp = raw;
if (raw.data && typeof raw.data === 'string') {
  try { wp = JSON.parse(raw.data); } catch (e) { wp = raw; }
} else if (raw.data && typeof raw.data === 'object') {
  wp = raw.data;
}
const assignee = wp._links?.assignee?.title || wp._links?.assignee?.name || 'Unassigned';
const status = wp._links?.status?.title || '';
const subject = wp.subject || '';
const desc = (wp.description && wp.description.raw) ? wp.description.raw : '';
const meta = $('Prepare Task Overview').first().json;
const userQuestion = String($('Code in JavaScript2').first().json.text || '').trim();

const sd = $getWorkflowStaticData('global');
const ch = String(meta.channelId || '').trim() || 'unknown';
const convKey = 'overview_' + ch;
if (!sd.conversations) sd.conversations = {};
const mem = { ...(sd.conversations[convKey] || {}) };
if (!mem.messages) mem.messages = [];
mem.lastTaskId = wp.id || meta.task_id;
mem.lastTaskTitle = subject;
mem.lastOverviewFocus = 'task';
sd.conversations[convKey] = mem;

const prior = mem.messages.slice(0, -1);
const conversationContext = prior.length
  ? prior.slice(-12).map((m) => (m.role === 'user' ? 'User' : 'Assistant') + ': ' + m.text).join(String.fromCharCode(10))
  : '(No prior messages in this channel.)';

return [{ json: {
  task_id: wp.id || meta.task_id,
  subject,
  description: desc,
  assignee,
  status,
  channelId: meta.channelId,
  userId: meta.userId,
  thread_ts: meta.thread_ts,
  ts: meta.ts,
  userQuestion,
  conversationContext
} }];

const j = $input.first().json;
const msg = j.error === 'NO_TASK_ID'
  ? 'Please include a numeric task (work package) ID so I can summarize that task, e.g. "overview of task 123".'
  : 'Could not load that task from OpenProject. Check the task ID.';
return [{ json: {
  slackText: msg,
  slackUserId: j.userId,
  channelId: j.channelId,
  thread_ts: j.thread_ts,
  ts: j.ts
} }];

const ai = $('Code in JavaScript2').first().json;
const sd = $getWorkflowStaticData('global');
if (!sd.conversations) sd.conversations = {};
const ch = String(ai.channelId || '').trim() || 'unknown';
const convKey = 'overview_' + ch;
const prev = sd.conversations[convKey] || {};
const mem = { ...prev, messages: [...(prev.messages || [])] };

let tid = ai.task_id != null ? ai.task_id : (Array.isArray(ai.task_ids) && ai.task_ids.length ? ai.task_ids[0] : null);
if (tid === null || tid === undefined || tid === '') {
  if (prev.lastTaskId != null && prev.lastTaskId !== '') tid = prev.lastTaskId;
}
if (tid === null || tid === undefined || tid === '') {
  const tx = String(ai.text || '');
  const m = tx.match(/\b(?:task|wp)\s*#?(\d{2,})\b/i) || tx.match(/#(\d{2,})\b/) || tx.match(/\boverview\s+of\s+task\s+(\d+)\b/i);
  if (m) tid = parseInt(m[1], 10);
}

if (tid === null || tid === undefined || tid === '') {
  return [{ json: {
    error: 'NO_TASK_ID',
    channelId: ai.channelId,
    userId: ai.userId,
    thread_ts: ai.thread_ts,
    ts: ai.ts
  } }];
}

const userText = String(ai.text || '').trim();
mem.messages.push({ role: 'user', text: userText, at: Date.now() });
if (mem.messages.length > 24) mem.messages = mem.messages.slice(-24);
sd.conversations[convKey] = mem;

return [{ json: {
  task_id: Number(tid),
  channelId: ai.channelId,
  userId: ai.userId,
  thread_ts: ai.thread_ts,
  ts: ai.ts
} }];

const j = $input.first().json;
const err = j.error || '';
let msg = 'Could not process your request.';
if (err === 'NO_PROJECT_NAME') {
  msg = '*Project name missing* — I could not detect which project you mean. Please send the *exact project name* or *project identifier* as it appears in OpenProject.';
} else if (err === 'PROJECT_NOT_FOUND') {
  msg = 'No matching open project was found for "' + (j.projectName || 'that name') + '". Please reply with the *exact project name* or *identifier* from OpenProject (copy from the project list if needed).';
}
return [{ json: {
  slackText: msg,
  slackUserId: j.userId,
  channelId: j.channelId,
  thread_ts: j.thread_ts,
  ts: j.ts
} }];

const data = $input.first().json;
const allProjects = data.projects || [];
const aiData = $('Code in JavaScript2').first().json;
const prep = $('Match Overview Project').first().json;
const raw = (prep.extractedProjectName || aiData.ProjectRaw || '').trim();
const slugField = (aiData.Project || '').trim();

function norm(s) {
  return String(s ?? '')
    .toLowerCase()
    .replace(/[-_]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

let searchName = (aiData.Project || '').trim().toLowerCase();
if (!searchName && raw) {
  searchName = raw.toLowerCase().replace(/\s+/g, '-');
}

const rawNorm = norm(raw);

function buildSearchNorms() {
  const set = new Set();
  const add = (v) => { const n = norm(v); if (n) set.add(n); };
  add(raw);
  if (slugField) {
    add(slugField);
    add(slugField.replace(/-/g, ' '));
  }
  return [...set];
}

function partialSimilarityOk(queryNorm, fieldNorm) {
  if (!queryNorm || !fieldNorm) return false;
  const a = queryNorm.length <= fieldNorm.length ? queryNorm : fieldNorm;
  const b = queryNorm.length >= fieldNorm.length ? queryNorm : fieldNorm;
  if (a.length < 3) return false;
  if (b.includes(a)) {
    const ratio = a.length / b.length;
    return ratio >= 0.32 || a.length >= 5;
  }
  return false;
}

function findMatchFallback(projects, searchNorms) {
  for (const proj of projects) {
    const nameN = norm(proj.name || '');
    const identN = norm(proj.identifier || '');
    for (const sk of searchNorms) {
      if (sk && (nameN === sk || identN === sk)) return proj;
    }
  }
  for (const proj of projects) {
    const nameN = norm(proj.name || '');
    for (const sk of searchNorms) {
      const tokens = sk.split(' ').filter((t) => t.length > 0);
      if (tokens.length >= 2 && tokens.every((t) => nameN.includes(t))) return proj;
    }
  }
  for (const proj of projects) {
    const nameN = norm(proj.name || '');
    const identN = norm(proj.identifier || '');
    for (const sk of searchNorms) {
      if (!sk || sk.length < 2) continue;
      if (partialSimilarityOk(sk, nameN) || partialSimilarityOk(sk, identN)) return proj;
      if (partialSimilarityOk(nameN, sk) || partialSimilarityOk(identN, sk)) return proj;
    }
  }
  return null;
}

if (allProjects.length === 0) {
  return [{ json: {
    error: 'PROJECT_NOT_FOUND',
    channelId: aiData.channelId,
    userId: aiData.userId,
    thread_ts: aiData.thread_ts,
    ts: aiData.ts,
    projectName: raw
  } }];
}

let matched = null;

for (const proj of allProjects) {
  if ((proj.identifier || '').toLowerCase() === searchName) {
    matched = proj;
    break;
  }
}
if (!matched) {
  for (const proj of allProjects) {
    const nameSlug = (proj.name || '').toLowerCase().replace(/\s+/g, '-');
    if (nameSlug === searchName) {
      matched = proj;
      break;
    }
  }
}
if (!matched) {
  for (const proj of allProjects) {
    if ((proj.name || '').toLowerCase() === searchName.replace(/-/g, ' ')) {
      matched = proj;
      break;
    }
  }
}
if (!matched) {
  for (const proj of allProjects) {
    const name = (proj.name || '').toLowerCase();
    const ident = (proj.identifier || '').toLowerCase();
    if (name.includes(searchName) || ident.includes(searchName) || searchName.includes(name) || searchName.includes(ident)) {
      matched = proj;
      break;
    }
  }
}

if (!matched && rawNorm) {
  for (const proj of allProjects) {
    const hp = norm(proj.hierarchy?.hierarchyPath || proj.name || '');
    if (hp === rawNorm || hp.includes(rawNorm) || rawNorm.includes(hp)) {
      matched = proj;
      break;
    }
  }
}

if (!matched && rawNorm) {
  for (const proj of allProjects) {
    if (norm(proj.name) === rawNorm || norm(proj.identifier) === rawNorm) {
      matched = proj;
      break;
    }
  }
}

if (!matched) {
  const searchNorms = buildSearchNorms();
  if (searchNorms.length > 0) {
    matched = findMatchFallback(allProjects, searchNorms);
  }
}

if (!matched) {
  return [{ json: {
    error: 'PROJECT_NOT_FOUND',
    channelId: aiData.channelId,
    userId: aiData.userId,
    thread_ts: aiData.thread_ts,
    ts: aiData.ts,
    projectName: raw
  } }];
}

const hierarchyPath = matched.hierarchy?.hierarchyPath || matched.name || '';

try {
  const sdM = $getWorkflowStaticData('global');
  if (!sdM.conversations) sdM.conversations = {};
  const chM = String(aiData.channelId || '').trim() || 'unknown';
  const convKeyM = 'overview_' + chM;
  const prevM = sdM.conversations[convKeyM] || {};
  sdM.conversations[convKeyM] = {
    ...prevM,
    lastProjectId: matched.id,
    lastProjectName: matched.name,
    lastProjectIdentifier: matched.identifier,
    lastOverviewFocus: 'project',
    messages: prevM.messages || []
  };
} catch (e) {}

return [{ json: {
  projectId: matched.id,
  projectName: matched.name,
  projectIdentifier: matched.identifier,
  hierarchyPath,
  channelId: aiData.channelId,
  userId: aiData.userId,
  thread_ts: aiData.thread_ts,
  ts: aiData.ts
} }];

parameters.text:
=You are helping a Slack user with questions about ONE OpenProject project.

USER'S CURRENT MESSAGE (you MUST address this — it is the primary instruction):
{{ $json.userQuestion }}

RECENT CONVERSATION IN THIS SLACK CHANNEL (shared memory for the channel; OpenProject facts below are ground truth):
{{ $json.conversationContext }}

PRIORITY (OVERRIDES EVERYTHING BELOW):
- If the user asks for a specific **format** (bullet points, numbered list, table, headings, one paragraph, short vs long, etc.), follow it exactly.
- If they ask for a specific **language** (English, Urdu in Arabic script, or Roman Urdu), write the entire answer in that language.
- If they ask for both format and language, satisfy both.
- Only when they give no preference, use the default rules that follow.

DEFAULT LANGUAGE (when not specified): Mirror the language of their message (English, Urdu script, or Roman Urdu) when natural.

DATA FROM OPENPROJECT (ground truth; do not invent):
- Project name: {{ $json.name }}
- Identifier: {{ $json.identifier }}
- Hierarchy path: {{ $json.hierarchyPath || 'n/a' }}
- **Full description** (use this for detailed and follow-up questions):
{{ $json.description }}
- Status: {{ $json.status }}
- Member count: {{ $json.membershipCount ?? 'unknown' }}
- Sample members: {{ $json.membershipNamesSample || 'n/a' }}

RESPONSE RULES (when the user did not specify a custom format):
1) **Broad / first-time requests** ("overview", "what is this project", "summarize the project") — Give a structured, Slack-friendly overview: what the project is, purpose/use case from the description, hierarchy if useful, approximate team size.

2) **Specific or follow-up questions** (e.g. "explain footfall counting", "gender counting", "how does X work", "tell me about section Y") — **Do NOT** repeat the same generic overview bullet list. Read the **full description** and produce a **new, targeted** answer that focuses **only** on what they asked, with **detail** from the text.

3) If the description does not mention their topic, say clearly that it is not documented there; do not guess.

4) Use **more length and detail** when they ask for depth; stay shorter for generic overview-only requests.

Reply with Slack-ready text only (no JSON, no preamble).

If they gave no format or angle, consider whether they want a broad overview or a specific aspect—then answer accordingly: for a specific aspect, lead with a direct, detailed answer; avoid re-listing the whole project.

CHATBOT: Memory is per Slack channel (everyone in the channel shares this transcript). Use RECENT CONVERSATION for follow-ups so the user need not repeat project names when they clearly continue the same topic. If they ask something completely different, answer that new topic. Facts must still match OpenProject data in this prompt.

