// ========== STEP 1: PROJECT DATA PARSE KARO ==========
const httpResponse = $('HTTP Request1').first().json;
let project = httpResponse;

if (httpResponse.data && typeof httpResponse.data === 'string') {
  try {
    project = JSON.parse(httpResponse.data);
  } catch (e) {
    console.log("Project parse error:", e.message);
  }
}

// ========== STEP 2: MEMBERSHIPS DATA PARSE KARO ==========
// ⚠️ IMPORTANT: $input.first().json mein bhi "data" field mein string hai!
const memResponse = $input.first().json;
let mem = memResponse;

if (memResponse.data && typeof memResponse.data === 'string') {
  try {
    mem = JSON.parse(memResponse.data);
    console.log("✅ Parsed memberships from string");
  } catch (e) {
    console.log("Memberships parse error:", e.message);
    mem = memResponse;
  }
}

console.log("MEMBERSHIPS PARSED:", JSON.stringify(mem, null, 2));

// ========== STEP 3: MEMBERS EXTRACT KARO ==========
let elements = [];
let total = 0;

if (mem._embedded && mem._embedded.elements) {
  elements = mem._embedded.elements;
  total = mem.total || mem.count || elements.length;
  console.log("✅ Found", elements.length, "members");
}

// ========== STEP 4: MEMBER NAMES NIKALO ==========
const names = elements.map((el) => {
  const name = el._links?.principal?.title || '';
  return String(name).trim();
}).filter(Boolean);

console.log("MEMBER NAMES:", names);

// ========== STEP 5: DESCRIPTION EXTRACT KARO ==========
let description = 'No description stored.';
if (project.description?.raw) {
  description = project.description.raw;
} else if (project.description?.html) {
  description = project.description.html.replace(/<[^>]*>/g, ' ').trim();
}

// ========== STEP 6: USER QUESTION + CHANNEL MEMORY (one store per Slack channel) ==========
const aiCtx = $('Code in JavaScript2').first().json;
const userQuestion = String(aiCtx.text || '').trim();
const sdP = $getWorkflowStaticData('global');
if (!sdP.conversations) sdP.conversations = {};
const chP = String(aiCtx.channelId || '').trim() || 'unknown';
const convKeyP = 'overview_' + chP;
const prevP = sdP.conversations[convKeyP] || {};
const memP = { ...prevP, messages: [...(prevP.messages || [])] };
memP.messages.push({ role: 'user', text: userQuestion, at: Date.now() });
if (memP.messages.length > 24) memP.messages = memP.messages.slice(-24);
sdP.conversations[convKeyP] = memP;
const priorP = memP.messages.slice(0, -1);
const conversationContext = priorP.length
  ? priorP.slice(-12).map((m) => (m.role === 'user' ? 'User' : 'Assistant') + ': ' + m.text).join(String.fromCharCode(10))
  : '(No prior messages in this channel.)';

