  const parentId = (parentHref && parentHref !== 'null') ? parseInt(parentHref.split('/').pop(), 10) : null;
  const ancestors = (project._links && project._links.ancestors) ? project._links.ancestors : [];
  let hierarchyPath = projectName;
  let level = 0;
  if (ancestors.length > 0) {
    const ancestorNames = ancestors.map(a => a.title || '');
    hierarchyPath = [...ancestorNames, projectName].join(' > ');
    level = ancestors.length;
  }
  hierarchyById[projectId] = {
    projectId, projectName, projectIdentifier, hierarchyPath, level,
    isSubProject: parentId !== null, parentProjectId: parentId
