/** If the classifier left Project empty, derive a name from the user message */
function extractProjectNameFromMessage(text) {
  if (!text || typeof text !== 'string') return '';
  const t = text.replace(/\s+/g, ' ').trim();
  let m = t.match(/["']([^"']{2,120})["']/);
  if (m) return m[1].trim();
  m = t.match(/(?:overview|summary|about|explain)\s+(?:of|for)\s+(?:the\s+)?(?:project\s+)?["']?([^\.\n\?]+?)(?:\s*\.|\s*$|\?)/i);
  if (m) return m[1].replace(/\s+overview$/i, '').trim();
  m = t.match(/(?:project|for)\s+["']?([^"'\n\?]+?)["']?(?:\s+overview|\s*$|\s*\.|\s*\?)/i);
  if (m) return m[1].replace(/\s+overview$/i, '').trim();
  return '';
}

