function pad2(v) { return String(v).padStart(2, '0'); }

function ymdInTz(date, tz) {
  const p = new Intl.DateTimeFormat('en-CA', { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(date);
  const y = p.find((x) => x.type === 'year').value;
  const m = p.find((x) => x.type === 'month').value;
  const d = p.find((x) => x.type === 'day').value;
  return `${y}-${m}-${d}`;
}

function todayYmd(tz) {
  return ymdInTz(new Date(), tz);
}

/** Walk back hours until calendar date in tz changes (reliable "yesterday"). */
function yesterdayYmd(tz) {
  const ty = todayYmd(tz);
  let d = new Date();
  for (let h = 1; h <= 48; h++) {
    d = new Date(d.getTime() - 3600000);
    const ymd = ymdInTz(d, tz);
    if (ymd !== ty) return ymd;
  }
  return ty;
}

function tomorrowYmd(tz) {
  const ty = todayYmd(tz);
  let d = new Date();
  for (let h = 1; h <= 48; h++) {
    d = new Date(d.getTime() + 3600000);
    const ymd = ymdInTz(d, tz);
    if (ymd !== ty) return ymd;
  }
  return ty;
}

function parseExplicitDate(text) {
  const t = String(text || '');
  const iso = t.match(/\b(\d{4}-\d{2}-\d{2})\b/);
  if (iso) return iso[1];

  const dmy = t.match(/\b(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})\b/);
  if (dmy) {
    const dd = Number(dmy[1]);
    const mm = Number(dmy[2]);
    const yy = Number(dmy[3]);
    if (yy >= 2000 && mm >= 1 && mm <= 12 && dd >= 1 && dd <= 31) {
      return `${yy}-${pad2(mm)}-${pad2(dd)}`;
    }
  }
  return '';
}

function hasRelativeDateWords(text) {
  return /(yesterday|today|tomorrow|kal|previous day|last day|last night|next day|aaj)/i.test(String(text || ''));
}

function forgotYesterdaySignal(text) {
  const t = String(text || '');
  const forgot = /(forgot|missed|late update|didn't send|did not send|bhool|bhool gaya|bhool gya)/i.test(t);
  const yest = /(yesterday|kal|previous day|last day|last night)/i.test(t);
  return forgot && yest;
}

/** Map relative language to YYYY-MM-DD in DAILY_UPDATE_TZ (not UTC). */
function relativeActivityYmd(text, tz) {
  const t = String(text || '').toLowerCase();
  const hasToday = /\b(today|aaj)\b/i.test(text);
  const hasYesterday = /(yesterday|kal|previous day|last day|last night)/i.test(t);
  const hasTomorrow = /(tomorrow|next day)/i.test(t);

  if (hasTomorrow && !hasToday && !hasYesterday) return tomorrowYmd(tz);
  if (hasToday && hasYesterday && !forgotYesterdaySignal(text)) {
    return todayYmd(tz);
  }
  if (hasToday && !hasYesterday) return todayYmd(tz);
  if (hasYesterday && !hasToday) return yesterdayYmd(tz);
  if (hasToday) return todayYmd(tz);
  if (hasYesterday) return yesterdayYmd(tz);
  if (hasTomorrow) return tomorrowYmd(tz);
  return todayYmd(tz);
}

function fixStaleActivityYear(iso) {
  if (!iso || !/^\d{4}-\d{2}-\d{2}$/.test(iso)) return todayYmd(DAILY_UPDATE_TZ);
  const cy = parseInt(todayYmd(DAILY_UPDATE_TZ).slice(0, 4), 10);
  const y = parseInt(iso.slice(0, 4), 10);
  if (y >= cy - 1 && y <= cy + 1) return iso;
  return todayYmd(DAILY_UPDATE_TZ);
}

function inferDailyStatus(text) {
  const t = String(text || '').toLowerCase();
  if (/(completed|complete|done|finished|submitted|khatam)/.test(t)) return 'done';
  if (/(delay|delayed|not done|pending|late|tomorrow|more time)/.test(t)) return 'delayed';
  if (/(working|in progress|ongoing|continue|still working)/.test(t)) return 'in_progress';
  return '';
}

const inferredStatus = inferDailyStatus(userText);
const forgotPreviousDaySignal = /(forgot|missed|late update|didn't send|did not send|bhool|bhool gaya|bhool gya)/i.test(userText) && /(yesterday|kal|previous day|last day|last night|\d{4}-\d{2}-\d{2}|\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4})/i.test(userText);
const looksLikeDailyUpdate = userText.length > 15 && (/(yesterday|today|tomorrow|kal|activity|update|status|working|done|completed|delay|delayed|remark|remarks|forgot|missed)/i.test(userText));

if ((intent === 'done' || intent === 'delay') && !data.task_id && !Array.isArray(data.task_ids)) {
