const BASE_URL = 'https://projects.scraperrs.com';
const API_KEY  = '8700467d9591d98c4a00b753f3f7bd0e53bc96917798d7d1ad71091cf99475f2';

// Read from $json (workflow context — always available)
const projectName  = $json.ProjectRaw || $json.projectName || $json.Project || 'Unknown';
const daysBack     = $json.daysBack   || 7;
const dateRange    = $json.dateRangeLabel || 'Last 7 days';
const reportType   = 'project';

const authHeader = 'Basic ' + Buffer.from(`apikey:${API_KEY}`).toString('base64');

// ── 1. FETCH ALL PROJECTS ─────────────────────────────────────
let allProjects = [];
let offset = 0;
while (true) {
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE_URL}/api/v3/projects?pageSize=50&offset=${offset}`,
    headers: { Authorization: authHeader },
    json: true
  });
  const page = data._embedded?.elements || [];
  allProjects = allProjects.concat(page);
  if (page.length < 50) break;
  offset += 50;
  if (offset > 2000) break;
}

// ── 2. FIND PROJECT ──────────────────────────────────────────
const norm2 = s => (s || '').toLowerCase().replace(/[-_]/g,' ').replace(/[^\w\s]/g,'').replace(/\s+/g,' ').trim();
const target  = norm2(projectName);
const matched = allProjects.find(p => norm2(p.name) === target)
             || allProjects.find(p => norm2(p.name).includes(target))
             || allProjects.find(p => target.includes(norm2(p.name)));

if (!matched) {
  return `❌ Project "${projectName}" not found. Available: ${allProjects.slice(0,8).map(p=>p.name).join(', ')}`;
}

// ── 3. FETCH WORK PACKAGES ───────────────────────────────────
let allWPs = [];
offset = 0;
while (true) {
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE_URL}/api/v3/projects/${matched.id}/work_packages?pageSize=100&offset=${offset}&embed[]=assignee&embed[]=status`,
    headers: { Authorization: authHeader },
    json: true
  });
  const page = data._embedded?.elements || [];
  allWPs = allWPs.concat(page);
  if (page.length < 100) break;
  offset += 100;
  if (offset > 10000) break;
}

// ── 4. NORMALIZE PACKAGES ────────────────────────────────────
const today  = new Date().toISOString().split('T')[0];
const cutoff = daysBack > 0
  ? new Date(Date.now() - daysBack * 86400000).toISOString().split('T')[0]
  : null;

const packages = allWPs.map(wp => {
  const rawStatus = wp._embedded?.status?.name || wp._links?.status?.title || 'Unknown';
  const dueDate   = wp.dueDate || null;
  const updatedAt = (wp.updatedAt || '').substring(0, 10);
  const closedAt  = (wp.closedAt  || '').substring(0, 10);
  return {
    id:        wp.id,
    subject:   wp.subject,
    status:    rawStatus,
    assignee:  wp._embedded?.assignee?.name || wp._links?.assignee?.title || 'Unassigned',
    dueDate,
    updatedAt,
    closedAt,
    isOverdue: rawStatus !== 'Closed' && dueDate && dueDate < today,
    inWindow:  !cutoff || (closedAt || updatedAt) >= cutoff
  };
});

// ── 5. NORMALIZE STATUS ──────────────────────────────────────
const norm = s => {
  const v = (s || '').toLowerCase();
  if (/done|closed|finish|complet/.test(v))               return 'Closed';
  if (/\bin progress\b|\bactive\b/.test(v))               return 'In Progress';
  if (/in testing|tested/.test(v))                        return 'Testing';
  if (/test|review|qa|staging/.test(v))                   return 'Testing';
  if (/\bnew\b|\bopen\b/.test(v))                         return 'New';
  if (/scheduled|specification|backlog|rejected/.test(v)) return 'Planned';
  return 'Other';
};

const pct = (n, t) => t === 0 ? '0%' : ((n/t)*100).toFixed(1)+'%';
const pad = (s, l) => String(s ?? '').substring(0, l).padEnd(l);
const total = packages.length;

let closed=0, inProg=0, newT=0, testing=0, planned=0, overdue=0;
const userMap={}, overdueList=[], recentDone=[], inProgList=[];
const inWindow = packages.filter(w => w.inWindow);

for (const wp of packages) {
  const st  = norm(wp.status);
  const usr = wp.assignee || 'Unassigned';

  if      (st === 'Closed')      { closed++;  if (wp.inWindow) recentDone.push(wp); }
  else if (st === 'In Progress') { inProg++;  inProgList.push(wp); }
  else if (st === 'Testing')       testing++;
  else if (st === 'New')           newT++;
  else if (st === 'Planned')       planned++;

  if (wp.isOverdue) { overdue++; overdueList.push(wp); }

  if (!userMap[usr]) userMap[usr] = { total:0, closed:0, inProg:0, testing:0, overdue:0 };
  userMap[usr].total++;
  if (st === 'Closed')           userMap[usr].closed++;
  else if (st === 'In Progress') userMap[usr].inProg++;
  else if (st === 'Testing')     userMap[usr].testing++;
  if (wp.isOverdue)              userMap[usr].overdue++;
}

// ── 6. BUILD REPORT ──────────────────────────────────────────
const ratio  = closed / (total || 1);
const filled = Math.round(ratio * 10);
const bar    = '█'.repeat(filled) + '░'.repeat(10 - filled) + ` ${pct(closed, total)}`;
const health = ratio >= 0.7 ? '🟢 On Track' : ratio >= 0.4 ? '🟡 In Progress' : '🔴 Needs Attention';

const windowTotal  = inWindow.length;
const windowClosed = inWindow.filter(w => norm(w.status) === 'Closed').length;
const windowProg   = inWindow.filter(w => norm(w.status) === 'In Progress').length;
const windowTest   = inWindow.filter(w => norm(w.status) === 'Testing').length;
const windowNew    = inWindow.filter(w => norm(w.status) === 'New').length;

const rows = [
  ['📁 Project',          matched.name],
  ['📅 Period',           dateRange],
  ['─────────────────────','──────────────────────'],
  ['📊 Total Tasks',      `${total}`],
  ['✅ Closed',           `${closed}   (${pct(closed,  total)} of all)`],
  ['🔄 In Progress',      `${inProg}   (${pct(inProg,  total)})`],
  ['🧪 Testing',          `${testing}   (${pct(testing, total)})`],
  ['🆕 New',              `${newT}   (${pct(newT,    total)})`],
  ['📋 Planned',          `${planned}   (${pct(planned, total)})`],
  ['⚠️  Overdue',         `${overdue}   (${pct(overdue, total)})`],
  ['─────────────────────','──────────────────────'],
  ['🗓️  Active In Period', `${windowTotal} tasks`],
  ['   ↳ Closed',         `${windowClosed}   (${pct(windowClosed, windowTotal)})`],
  ['   ↳ In Progress',    `${windowProg}   (${pct(windowProg,   windowTotal)})`],
  ['   ↳ Testing',        `${windowTest}   (${pct(windowTest,   windowTotal)})`],
  ['   ↳ New',            `${windowNew}   (${pct(windowNew,    windowTotal)})`],
  ['─────────────────────','──────────────────────'],
  ['📈 Progress',         bar],
  ['💚 Health',           health],
];

const tbl = rows.map(([m, v]) => `  ${pad(m, 22)}${v}`).join('\n');
const outputs = [`*📊 Project Report — ${matched.name}*\n\`\`\`\n${tbl}\n\`\`\``];

if (recentDone.length) {
  outputs.push(
    `*✅ Completed This Period (${recentDone.length}):*\n` +
    recentDone.slice(0,10).map(w => `• \`#${w.id}\` ${w.subject}\n  └ _${w.assignee}_`).join('\n')
  );
}

if (overdueList.length) {
  outputs.push(
    `*⚠️ Overdue (${overdueList.length}):*\n` +
    overdueList.slice(0,10).map(w => `• \`#${w.id}\` ${w.subject}\n  └ _${w.assignee}_ · due: ${w.dueDate}`).join('\n')
  );
}

if (inProgList.length) {
  outputs.push(
    `*🔄 In Progress (${inProgList.length}):*\n` +
    inProgList.slice(0,8).map(w => `• \`#${w.id}\` ${w.subject}\n  └ _${w.assignee}_`).join('\n')
  );
}

// Assignee table
const hdr = '| Assignee             | Total | Done  | Prog  | Test  | Over  | Done% |';
const sep = '|----------------------|-------|-------|-------|-------|-------|-------|';
const assigneeRows = Object.entries(userMap)
  .sort((a,b) => b[1].total - a[1].total)
  .map(([u,d]) =>
    `| ${pad(u,20)} | ${pad(d.total,5)} | ${pad(d.closed,5)} | ${pad(d.inProg,5)} | ${pad(d.testing,5)} | ${pad(d.overdue,5)} | ${pad(pct(d.closed,d.total),5)} |`
  );
outputs.push(`*👤 Assignee Breakdown*\n\`\`\`\n${[hdr,sep,...assigneeRows].join('\n')}\n\`\`\``);

return outputs.join('\n\n');

