if (!inputProject) inputProject = ($json.ProjectRaw   || '').trim();
if (!inputProject) inputProject = ($json.projectName  || '').trim();
if (!inputProject) inputProject = ($json.Project      || '').trim();

if (!isNaN(parseInt($json.days_back, 10))) daysBack = parseInt($json.days_back, 10);
if (!isNaN(parseInt($json.daysBack,  10))) daysBack = parseInt($json.daysBack,  10);

if (!inputProject) {
  return JSON.stringify({ error: 'project_name missing', received: $json });
}

const authHeader = 'Basic ' + Buffer.from(`apikey:${API_KEY}`).toString('base64');

try {

  // 1. FETCH ALL PROJECTS
  let allProjects = [];
  let offset = 0;

  while (true) {
    const data = await this.helpers.httpRequest({
      method: 'GET',
      url: `${BASE_URL}/api/v3/projects?pageSize=50&offset=${offset}`,
      headers: { Authorization: authHeader },
      json: true
    });
    const page = data._embedded?.elements || [];
    allProjects = allProjects.concat(page);
    if (page.length < 50) break;
    offset += 50;
    if (offset > 2000) break;
  }

  // 2. FIND MATCHING PROJECT
  const norm = s => (s || '').toLowerCase().replace(/[-_]/g, ' ').replace(/[^\w\s]/g, '').replace(/\s+/g, ' ').trim();

  const target  = norm(inputProject);
  const matched = allProjects.find(p => norm(p.name) === target)
               || allProjects.find(p => norm(p.name).includes(target))
               || allProjects.find(p => target.includes(norm(p.name)));

  if (!matched) {
    return JSON.stringify({
      error: `Project not found: "${inputProject}"`,
      suggestions: allProjects.slice(0, 10).map(p => p.name)
    });
  }

  const projectId = matched.id;

  // 3. FETCH WORK PACKAGES
  let allWPs = [];
  offset = 0;

  while (true) {
    const data = await this.helpers.httpRequest({
      method: 'GET',
      url: `${BASE_URL}/api/v3/projects/${projectId}/work_packages?pageSize=100&offset=${offset}&embed[]=assignee&embed[]=status`,
      headers: { Authorization: authHeader },
      json: true
    });
    const page = data._embedded?.elements || [];
    allWPs = allWPs.concat(page);
    if (page.length < 100) break;
    offset += 100;
    if (offset > 10000) break;
  }

  // 4. NORMALIZE + DATE FILTER
  const today  = new Date().toISOString().split('T')[0];
  const cutoff = daysBack > 0
    ? new Date(Date.now() - daysBack * 86400000).toISOString().split('T')[0]
    : null;

  const packages = allWPs.map(wp => {
    const rawStatus =
      wp._embedded?.status?.name ||
      wp._links?.status?.title   ||
      'Unknown';

    const dueDate   = wp.dueDate || null;
    const updatedAt = (wp.updatedAt || '').substring(0, 10);
    const closedAt  = (wp.closedAt  || '').substring(0, 10);
    const effectiveDate = closedAt || updatedAt;

    return {
      id:        wp.id,
      subject:   wp.subject,
      status:    rawStatus,
      assignee:  wp._embedded?.assignee?.name || wp._links?.assignee?.title || 'Unassigned',
      priority:  wp._links?.priority?.title || '',
      type:      wp._links?.type?.title     || '',
      dueDate,
      startDate:  wp.startDate || null,
      createdAt: (wp.createdAt || '').substring(0, 10),
      updatedAt,
      closedAt,
      isOverdue: rawStatus !== 'Closed' && dueDate && dueDate < today,
      inWindow:  !cutoff || effectiveDate >= cutoff
    };
  });

  // 5. RETURN
  return JSON.stringify({
    project:      matched.name,
    total:        packages.length,
    workPackages: packages
  });

} catch (err) {
  return JSON.stringify({ error: err.message });
}

const out = $input.first().json;
const text = String(out.output || out.text || '').trim();
const ai = $('Code in JavaScript2').first().json;
const sd = $getWorkflowStaticData('global');
if (!sd.conversations) sd.conversations = {};
const ch = String(ai.channelId || '').trim() || 'unknown';
const convKey = 'overview_' + ch;
const prev = sd.conversations[convKey] || {};
const mem = { ...prev, messages: [...(prev.messages || [])] };
if (text) mem.messages.push({ role: 'assistant', text, at: Date.now() });
if (mem.messages.length > 24) mem.messages = mem.messages.slice(-24);
sd.conversations[convKey] = mem;
return [{ json: out }];

